import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";

export const useLogoutHandler = () => {
  const navigate = useNavigate();
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const backClickCountRef = useRef(0);
  const navigateRef = useRef(navigate);

  // Keep navigate ref updated
  useEffect(() => {
    navigateRef.current = navigate;
  }, [navigate]);

  // Handle logout
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setShowLogoutModal(false);
    backClickCountRef.current = 0; // Reset counter
    navigateRef.current("/login", { replace: true });
  };

  // Handle canceling logout (staying logged in) - resets back button counter
  const handleStayLoggedIn = () => {
    setShowLogoutModal(false);
    backClickCountRef.current = 0; // Reset counter when user chooses to stay
  };

  // Handle opening logout modal (from button click)
  const openLogoutModal = () => {
    setShowLogoutModal(true);
  };

  // Prevent back button navigation to login page
  useEffect(() => {
    // Replace current state to prevent going back without user acknowledgment
    window.history.replaceState({ isDashboard: true }, "", window.location.pathname);

    // Listen for back button clicks
    const handlePopState = () => {
      backClickCountRef.current++;

      if (backClickCountRef.current === 1) {
        // First back click: show logout modal and prevent navigation
        setShowLogoutModal(true);
        // Replace state to prevent actual back navigation
        window.history.replaceState({ isDashboard: true }, "", window.location.pathname);
      } else if (backClickCountRef.current >= 2) {
        // Second back click: proceed with logout and redirect via React Router
        // Remove event listener first to allow normal navigation
        window.removeEventListener("popstate", handlePopState);
        // Logout and navigate
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        setShowLogoutModal(false);
        backClickCountRef.current = 0;
        navigateRef.current("/login", { replace: true });
      }
    };

    window.addEventListener("popstate", handlePopState);

    return () => {
      window.removeEventListener("popstate", handlePopState);
    };
  }, []);

  return { 
    handleLogout, 
    handleStayLoggedIn,
    showLogoutModal, 
    setShowLogoutModal: openLogoutModal
  };
};
